def draw_char(display, ch, x, y, r, g, b, size="large"):
    """Draw anti-aliased character with additive blending.

    Args:
        display: display object with add_pixel(x, y, r, g, b) method
        ch: character to draw
        x, y: top-left position
        r, g, b: text color (0-255 each)
        size: "large" or "small"
    """
    if size == "large":
        w, h, data = LARGE_WIDTH, LARGE_HEIGHT, _LARGE_DATA.get(ch)
    else:
        w, h, data = SMALL_WIDTH, SMALL_HEIGHT, _SMALL_DATA.get(ch)
    if data is None:
        return
    for row in range(h):
        row_off = row * w
        for col in range(w):
            idx = row_off + col
            level = (data[idx >> 2] >> ((3 - (idx & 3)) << 1)) & 3
            if level:
                display.add_pixel(x + col, y + row,
                                  r * level // 3, g * level // 3,
                                  b * level // 3)


def measure_string(text, size="large", spacing=2):
    """Return pixel width of a string."""
    if size == "large":
        w = LARGE_WIDTH
    else:
        w = SMALL_WIDTH
    n = len(text)
    if n == 0:
        return 0
    return n * w + (n - 1) * spacing


def draw_string(display, text, x, y, r, g, b, size="large", spacing=2):
    """Draw a string of characters with additive blending."""
    if size == "large":
        w = LARGE_WIDTH
    else:
        w = SMALL_WIDTH
    for ch in text:
        draw_char(display, ch, x, y, r, g, b, size)
        x += w + spacing

